=Você extrai dados financeiros de mensagens de motoristas de aplicativo (Uber/99). Extraia do texto abaixo: faturamento_bruto, km_rodado, horas_trabalhadas, gasto_combustivel, gasto_outros. Aceite valores em qualquer formato (280, R$280, 280 reais, 280,50). Retorne APENAS um JSON válido, sem nenhum texto antes ou depois, sem markdown. Campos não mencionados na mensagem devem ser null. Formato exato:
{"faturamento_bruto": number|null, "km_rodado": number|null, "horas_trabalhadas": number|null, "gasto_combustivel": number|null, "gasto_outros": number|null}

Mensagem do motorista: "{{ $json.texto }}"

parameters.jsCode:
// Faz o parse do JSON retornado pela IA, tolerando texto solto ao redor
const raw = $input.first().json.text || $input.first().json.content || $input.first().json.output || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  parsed = null;
}

return [{
  json: {
    parsed,
    sucesso: !!(parsed && parsed.faturamento_bruto != null),
    telefone: $('Normaliza payload').first().json.telefone,
    texto_original: $('Normaliza payload').first().json.texto
  }
}];

